('computer-science:2-1-2-designing-creating-and-refining-algorithms:exam:7095cbd1', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'exam', 'mcq', 1, '{"num": "Q1", "question": "<p>Tick <strong>one</strong> box to identify the flowchart symbol used to show a decision, such as testing IF a value meets a condition.</p>", "options": ["Diamond", "Rectangle", "Parallelogram", "Terminal (stadium) shape"], "hint": "Which shape has two exits — a Yes branch and a No branch?"}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul><li><strong>Diamond</strong></li></ul>\n</div>", "modelAnswer": "Diamond."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:exam:17ba444c', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'exam', 'mcq', 1, '{"num": "Q2", "question": "<p>A program runs without crashing, but a shop''s discount calculator always gives an answer that is £10 too high. Tick <strong>one</strong> box to identify the type of error.</p>", "options": ["A syntax error, since the discount value itself is calculated a small amount wrong each time", "A logic error", "A runtime error caused by the translator being unable to understand one of the keywords", "A boolean error, because the calculation depends on a Boolean AND/OR condition somewhere in the code"], "hint": "The program runs successfully — it just produces the wrong number. Does that sound like a broken rule, or a flawed calculation?"}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul><li><strong>Logic error</strong> — the program runs, but the calculation itself is wrong.</li></ul>\n</div>", "modelAnswer": "A logic error."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:exam:e5ae2086', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'exam', 'mcq', 1, '{"num": "Q13", "question": "<p>Tick <strong>one</strong> box to identify what ''refining'' an algorithm means.</p>", "options": ["Improving an algorithm that already works, without changing what it does", "Fixing a logic error in an algorithm so that it finally gives the mathematically correct result every time", "Fixing a syntax error so that the program will run", "Rewriting the algorithm completely to solve a different problem"], "hint": "Refining assumes the algorithm is already CORRECT — it''s about making it better, not fixing it."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul><li><strong>Improving an algorithm that already works, without changing what it does</strong></li></ul>\n</div>", "modelAnswer": "Improving an algorithm that already works, without changing what it does."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:mcq:6680f36d', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'mcq', 'mcq', 1, '{"question": "Which of these is NOT one of the three parts of IPO analysis?", "options": ["Inputs", "Processes", "Outputs", "Operators"]}'::jsonb, '{"answer": 3, "explain": "IPO stands for Inputs, Processes and Outputs. Operators (like MOD or AND) are not one of the three parts of this analysis."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:mcq:6756fea7', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'mcq', 'mcq', 1, '{"question": "Which flowchart symbol shows an input or an output step?", "options": ["Parallelogram", "Diamond", "Rectangle", "Terminal (stadium) shape"]}'::jsonb, '{"answer": 0, "explain": "A parallelogram represents an input or an output. Diamonds are decisions, rectangles are processes, and terminals mark start/stop."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:mcq:c4531297', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'mcq', 'mcq', 1, '{"question": "Which flowchart symbol marks the start or the stop of an algorithm?", "options": ["Terminal (stadium) shape", "Rectangle with double side bars, used for a sub-program instead", "Diamond, which is actually used for decisions rather than start/stop", "Parallelogram, which is actually used for input and output instead"]}'::jsonb, '{"answer": 0, "explain": "The terminal (stadium/rounded) shape marks the start or stop of a flowchart. The others represent sub-programs, decisions, and input/output."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:mcq:dd03758d', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'mcq', 'mcq', 1, '{"question": "Which type of error stops a program from running at all?", "options": ["Logic error", "Syntax error", "Runtime warning", "Boolean error"]}'::jsonb, '{"answer": 1, "explain": "A syntax error breaks the rules of the language, so the program cannot even run until it is fixed. A logic error still runs, just with the wrong result."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:mcq:1e748344', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'mcq', 'mcq', 1, '{"question": "Which type of error allows a program to run, but produces the wrong result?", "options": ["Syntax error", "Logic error", "Compilation error", "Translation error"]}'::jsonb, '{"answer": 1, "explain": "A logic error obeys the rules of the language and runs successfully, but the programmer''s flawed reasoning means the output is wrong."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:mcq:fe2f4075', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'mcq', 'mcq', 1, '{"question": "What is the main purpose of a trace table?", "options": ["To record the value of each variable as an algorithm runs, line by line", "To list every syntax error that the translator finds anywhere in the whole algorithm before it will run", "To draw the flowchart symbols used by an algorithm", "To count how many variables an algorithm uses in total"]}'::jsonb, '{"answer": 0, "explain": "A trace table tracks how each variable''s value changes as the algorithm executes, one line (and one loop pass) at a time — it is a way of testing an algorithm by hand."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:mcq:148d7d33', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'mcq', 'mcq', 1, '{"question": "What is a structure diagram used for?", "options": ["Showing how a problem is broken down into smaller sub-tasks, as a hierarchy", "Showing the exact order that a program''s variables are declared in memory", "Showing which flowchart symbols are the correct ones to use", "Showing precisely how much memory an algorithm will use once it has been fully compiled and is running"]}'::jsonb, '{"answer": 0, "explain": "A structure diagram (hierarchy chart) shows top-down decomposition — how a problem splits into smaller sub-tasks. It does not show memory use, declaration order or flowchart symbol choice."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:mcq:f00921a9', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'mcq', 'mcq', 1, '{"question": "Which construct is being used when an if statement is placed inside another if statement?", "options": ["Nesting", "Sequencing", "Casting", "Validation"]}'::jsonb, '{"answer": 0, "explain": "Placing one construct inside another — such as an if inside an if, or an if inside a loop — is called nesting."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:mcq:6c1b2390', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'mcq', 'mcq', 1, '{"question": "A for loop is missing its closing ''next i'' line. What type of error is this?", "options": ["Logic error", "Syntax error", "Design error", "Output error"]}'::jsonb, '{"answer": 1, "explain": "The for loop''s structure is incomplete, breaking the rules of the language — the program will not run until ''next i'' is added. That makes it a syntax error."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:mcq:e776d891', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'mcq', 'mcq', 1, '{"question": "A for loop is written as ''for i = 1 to 20'' when only 10 passes were wanted. What type of error is this, once the loop DOES run?", "options": ["Logic error", "Syntax error", "Compiler error", "Interpreter error"]}'::jsonb, '{"answer": 0, "explain": "The loop runs perfectly happily (it follows the rules), it just repeats the wrong number of times — a flawed piece of logic, not a broken rule. That makes it a logic error."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:mcq:95f9021a', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'mcq', 'mcq', 1, '{"question": "What does ''refining'' an algorithm mean?", "options": ["Improving an algorithm that already works, without changing what it does", "Fixing a syntax error in a program so that a completely broken piece of code is finally able to run at all", "Correcting a logic error so the output finally becomes right", "Deleting the algorithm and starting again from a blank page"]}'::jsonb, '{"answer": 0, "explain": "Refining means improving a CORRECT algorithm — e.g. making it more efficient, readable or robust — not fixing an error. Fixing broken code is correcting it, not refining it."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:mcq:bd214b72', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'mcq', 'mcq', 1, '{"question": "Which pair correctly matches the flowchart symbol to its meaning?", "options": ["Diamond = decision, Parallelogram = input/output", "Diamond = input/output, Rectangle = decision", "Parallelogram = decision, Rectangle = sub-program", "Rectangle = start/stop, Diamond = process"]}'::jsonb, '{"answer": 0, "explain": "A diamond represents a decision (splitting the flow into Yes/No), and a parallelogram represents an input or output — the other pairings mix up the symbols."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:tf:a6ffb2fa', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'tf', 'tf', 1, '{"question": "A syntax error stops a program from running at all."}'::jsonb, '{"answer": true, "explain": "Correct — a syntax error breaks the rules of the language, so the program cannot run until it is fixed."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:tf:f7952b42', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'tf', 'tf', 1, '{"question": "A logic error always causes the program to crash immediately."}'::jsonb, '{"answer": false, "explain": "A logic error runs without crashing — it just gives the wrong result. Crashing/not running at all describes a syntax error."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:tf:5b576498', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'tf', 'tf', 1, '{"question": "A trace table is used to record the value of variables as an algorithm runs."}'::jsonb, '{"answer": true, "explain": "Correct — that is exactly what a trace table is for, updated line by line (and pass by pass) as the algorithm executes."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:tf:7705317d', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'tf', 'tf', 1, '{"question": "In a flowchart, a diamond symbol always represents an input or output step."}'::jsonb, '{"answer": false, "explain": "A diamond represents a decision. A parallelogram is used for input/output steps."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:tf:8d1bbaf4', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'tf', 'tf', 1, '{"question": "A structure diagram shows a problem broken down into smaller sub-tasks as a hierarchy."}'::jsonb, '{"answer": true, "explain": "Correct — this is top-down decomposition, shown as a hierarchy (like a family tree) with the whole problem at the top."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:tf:82f7d06c', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'tf', 'tf', 1, '{"question": "IPO stands for Inputs, Processes and Outputs."}'::jsonb, '{"answer": true, "explain": "Correct — analysing a problem''s inputs, processes and outputs is done before writing an algorithm."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:tf:faa0a6ac', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'tf', 'tf', 1, '{"question": "Refining an algorithm means changing what problem it solves."}'::jsonb, '{"answer": false, "explain": "Refining improves a CORRECT algorithm (efficiency, readability, robustness) without changing what it is meant to do."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:tf:f29c0ba3', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'tf', 'tf', 1, '{"question": "Nesting means placing one construct, such as an if statement, inside another."}'::jsonb, '{"answer": true, "explain": "Correct — an if inside an if, or an if inside a loop, are both examples of nesting."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:learn:f7652506', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'learn', 'mcq', 1, '{"readingTitle": "Analysing a problem: Inputs, Processes, Outputs (IPO)", "reading": "<h4>Break the problem down before you write any code</h4>\n<ul>\n<li>Before writing pseudocode, a programmer analyses the problem in terms of its <strong>Inputs, Processes and Outputs (IPO)</strong>.</li>\n<li><strong>Inputs</strong> — the data that must be entered or read in (from the user, a file, a sensor…).</li>\n<li><strong>Processes</strong> — what the program must DO to that data: calculations, decisions, repeats.</li>\n<li><strong>Outputs</strong> — what the program must produce or display as a result.</li>\n</ul>\n<p><strong>Example:</strong> \"Write a program that asks for three test scores and prints the average.\"</p>\n<div class=\"code-block\">Inputs:    three test scores\nProcesses: add the three scores together, then divide by 3\nOutputs:   the average score</div>\n<ul><li>Doing this FIRST stops you missing a requirement — and it is often asked for directly in the exam as an IPO table.</li></ul>", "question": "A program asks for a rectangle''s length and width, then displays its area. What is the PROCESS?", "options": ["Reading in the length and width values that the user has entered", "Multiplying the length by the width to work out the area", "Displaying the calculated area on the screen", "Storing the length and width as two separate named variables in memory, ready for later use"]}'::jsonb, '{"answer": 1, "explain": "The process is what the program DOES to the data — here, multiplying length by width. Reading in the values is the input; displaying the result is the output."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:learn:98fbe16b', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'learn', 'mcq', 1, '{"readingTitle": "Structure diagrams", "reading": "<h4>Top-down design: breaking a big problem into small tasks</h4>\n<ul>\n<li>A <strong>structure diagram</strong> shows how a problem is broken down into smaller sub-tasks, drawn as a <strong>hierarchy chart</strong> with the whole problem at the top.</li>\n<li>This process is called <strong>top-down design (decomposition)</strong>: start with the overall task, split it into a few major sub-tasks, then split each of those into smaller steps if needed.</li>\n<li>Example: \"Print a school report\" might decompose into <strong>Get student data</strong>, <strong>Calculate grades</strong>, <strong>Format report</strong> and <strong>Print report</strong> — each shown as a box beneath the main task.</li>\n</ul>\n<div class=\"code-block\">            Print School Report\n          /       |         |        \\\n   Get data   Calculate   Format    Print\n              grades      report    report</div>\n<ul><li>Each box can later be developed as its own sub-program (subroutine) — this is why structure diagrams and subroutines link together.</li></ul>", "question": "What does a structure diagram show?", "options": ["How a problem is broken down into smaller sub-tasks, arranged as a hierarchy", "The exact pseudocode that will be typed to solve the whole problem, line by line", "The order that variables are declared and given their very first starting values", "The flow of data backwards and forwards between every input and output device used"]}'::jsonb, '{"answer": 0, "explain": "A structure diagram (hierarchy chart) shows top-down decomposition — how a big problem splits into smaller sub-tasks. It does not show pseudocode, declaration order or literal data flow."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:learn:1120c16a', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'learn', 'mcq', 1, '{"readingTitle": "Flowchart symbols", "reading": "<h4>The shapes used to draw an algorithm</h4>\n<ul>\n<li>A <strong>flowchart</strong> shows an algorithm using standard symbols, joined by <strong>flow lines (arrows)</strong> that show the order the steps happen in.</li>\n<li><strong>Terminal (stadium / rounded rectangle)</strong> — marks the <strong>start</strong> or <strong>stop</strong> of the algorithm. There is exactly one start and at least one stop.</li>\n<li><strong>Parallelogram</strong> — an <strong>input</strong> (reading a value in) or an <strong>output</strong> (displaying a value).</li>\n<li><strong>Rectangle</strong> — a <strong>process</strong> step: a calculation or an assignment.</li>\n<li><strong>Diamond</strong> — a <strong>decision</strong>: asks a yes/no question, and the flow splits into two branches (used for selection AND for loop conditions).</li>\n<li><strong>Rectangle with double side bars</strong> — a <strong>sub-program (subroutine)</strong> call: a separate, named piece of the algorithm defined elsewhere.</li>\n<li><strong>Arrow (flow line)</strong> — shows the <strong>direction</strong> the algorithm runs in, connecting one symbol to the next.</li>\n</ul>", "question": "Which flowchart symbol is used for a decision, such as testing IF a value is greater than 10?", "options": ["A diamond, which splits the flow into a Yes branch and a No branch", "A rectangle with double side bars, because that shape always represents any kind of decision", "A parallelogram, because the value being tested must first be read in as an input", "A terminal (stadium) shape, since decisions always happen at the very start of a flowchart"]}'::jsonb, '{"answer": 0, "explain": "A decision is always shown with a diamond, with the flow splitting into two branches depending on the answer. Rectangles with side bars are sub-programs, parallelograms are input/output, and terminals mark start/stop."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:learn:e9c59480', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'learn', 'mcq', 1, '{"readingTitle": "Flowcharts: sequence and selection", "reading": "<h4>Sequence and selection drawn as a flowchart</h4>\n<ul>\n<li>In a flowchart, <strong>sequence</strong> is shown by process/input/output boxes joined one after another by arrows, top to bottom.</li>\n<li><strong>Selection</strong> is shown by a <strong>diamond</strong>: the flow arrives, the diamond asks a yes/no question, and the flow splits into a <strong>Yes</strong> branch and a <strong>No</strong> branch. The branches usually re-join further down before the flowchart continues.</li>\n</ul>\n<div class=\"code-compare\">\n<div><p class=\"code-label\">Flowchart (in words)</p><div class=\"code-block\">Start\n→ Input: age\n→ Decision: age &gt;= 18 ?\n   Yes → Output: \"Adult\"\n   No  → Output: \"Minor\"\n→ Stop</div></div>\n<div><p class=\"code-label\">Pseudocode (ERL)</p><div class=\"code-block\">age = input(\"Enter age: \")\nif age &gt;= 18 then\n  print(\"Adult\")\nelse\n  print(\"Minor\")\nendif</div></div>\n</div>", "question": "In a flowchart, how many arrows normally leave a decision (diamond) symbol?", "options": ["Two — one for the Yes branch and one for the No branch", "Just one, because a decision can only ever lead to a single outcome no matter what", "None at all, because a diamond always marks the very end of the whole flowchart", "Four, one for each of the possible answers a decision could ever have"]}'::jsonb, '{"answer": 0, "explain": "A decision diamond always has two exits — a Yes branch and a No branch — which is what makes selection possible in a flowchart."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:learn:b44a3f44', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'learn', 'mcq', 1, '{"readingTitle": "Flowcharts: iteration", "reading": "<h4>Showing a loop in a flowchart</h4>\n<ul>\n<li><strong>Iteration</strong> is shown using a diamond too — but this time one branch loops <strong>back</strong> to an earlier point in the flowchart instead of moving on, creating a cycle.</li>\n<li>A <strong>pre-condition loop</strong> (like <code>while</code>) puts the diamond <strong>before</strong> the repeated steps — the flow can skip the loop entirely if the condition is already false.</li>\n<li>A <strong>post-condition loop</strong> (like <code>do…until</code>) puts the diamond <strong>after</strong> the repeated steps — those steps always run at least once before the condition is tested.</li>\n</ul>\n<div class=\"code-block\">Start\n→ count = 0\n→ Decision: count &lt; 3 ?\n   Yes → Output: count → count = count + 1 → (back to Decision)\n   No  → Stop</div>", "question": "In a flowchart for a while loop, where is the decision diamond drawn relative to the repeated steps?", "options": ["Before the steps, so the loop can be skipped if the condition is already false", "After the steps, so that the repeated steps are always guaranteed to run through at least one time first", "In the middle of the steps, splitting them exactly in half every single time", "Nowhere, because loops in a flowchart never use a decision diamond at all"]}'::jsonb, '{"answer": 0, "explain": "A while (pre-condition) loop puts the diamond BEFORE the repeated steps, so the flow can skip the loop entirely if the condition is already false. A do…until loop puts it after, guaranteeing at least one pass."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:learn:e96e5d65', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'learn', 'mcq', 1, '{"readingTitle": "Creating an algorithm: from problem to pseudocode", "reading": "<h4>Turning a decomposed problem into pseudocode</h4>\n<ul>\n<li>Once a problem is broken into IPO and a structure diagram, each part is written up as <strong>pseudocode</strong> using the three constructs — sequence, selection, iteration — in <strong>ERL</strong>.</li>\n<li>A useful method: write each sub-task from the structure diagram as a short block of pseudocode, then put the blocks together in the right order.</li>\n</ul>\n<div class=\"code-block\">// Sub-task: get three scores and find the average\ntotal = 0\nfor i = 1 to 3\n  score = input(\"Enter score: \")\n  total = total + score\nnext i\naverage = total / 3\nprint(average)</div>\n<ul><li>Keep it simple and readable: use meaningful variable names (<code>total</code>, not <code>x</code>), and only use the constructs you actually need.</li></ul>", "question": "What is a sensible method for turning a structure diagram into pseudocode?", "options": ["Write each sub-task as a short block of pseudocode, then combine the blocks in the right order", "Write the whole algorithm in one single line so that it runs as fast as possible", "Start with the last sub-task in the diagram and work backwards to the first one", "Guess the pseudocode first without planning, and only draw the structure diagram afterwards once the code already works"]}'::jsonb, '{"answer": 0, "explain": "Writing each sub-task from the structure diagram as its own short block, then assembling the blocks in order, keeps the algorithm organised and matches how the problem was decomposed."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:learn:f52208e6', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'learn', 'mcq', 1, '{"readingTitle": "Interpreting an algorithm — determining its purpose", "reading": "<h4>Reading someone else''s code and working out what it does</h4>\n<ul>\n<li>The exam often gives you a short algorithm and asks you to state its <strong>purpose</strong> — what problem it solves — not to describe it line by line.</li>\n<li>Method: <strong>trace it mentally with a simple example</strong>, then describe the pattern in the outputs, not the individual steps.</li>\n</ul>\n<div class=\"code-block\">total = 0\ncount = 0\nfor i = 1 to 5\n  n = input(\"Enter a number: \")\n  total = total + n\n  count = count + 1\nnext i\nprint(total / count)</div>\n<ul><li>This algorithm reads 5 numbers, adds them up, and divides by how many there were — its <strong>purpose</strong> is: \"it calculates the <strong>average (mean)</strong> of 5 numbers entered by the user.\"</li></ul>", "question": "An algorithm reads 5 numbers, adds them together, then divides the total by 5. What is its PURPOSE?", "options": ["It calculates the average (mean) of 5 numbers entered by the user", "It only checks whether each of the 5 numbers entered is a positive number", "It sorts the 5 numbers into order from smallest to largest before displaying them", "It counts how many of the 5 numbers entered by the user are even numbers, one at a time"]}'::jsonb, '{"answer": 0, "explain": "Adding values then dividing by how many there were is the standard method for finding an average (mean) — that is the algorithm''s purpose, not sorting, validating or counting evens."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:learn:5105274e', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'learn', 'mcq', 1, '{"readingTitle": "Building a trace table", "reading": "<h4>Hand-tracing an algorithm, one line at a time</h4>\n<ul>\n<li>A <strong>trace table</strong> records the value of each variable <strong>every time it changes</strong>, so you can work out exactly what an algorithm does for given input(s) — without running it.</li>\n<li>Method: draw one column per variable (plus an output column). Go through the algorithm <strong>line by line</strong>. Every time a line changes a variable, write its new value in that column on a new row. For a loop, repeat this for <strong>every pass</strong>.</li>\n</ul>\n<div class=\"code-compare\">\n<div><p class=\"code-label\">Algorithm</p><div class=\"code-block\">total = 0\nfor i = 1 to 3\n  total = total + i\nnext i\nprint(total)</div></div>\n<div><p class=\"code-label\">Trace table</p><div class=\"code-block\">i  | total\n1  | 1\n2  | 3\n3  | 6\n\nOutput: 6</div></div>\n</div>\n<ul><li>Never skip a pass or guess — go slowly and mechanically, exactly as the computer would.</li></ul>", "question": "What is the golden rule for completing a trace table correctly?", "options": ["Go through the algorithm line by line, recording a variable''s new value every time it changes", "Skim the algorithm once and write down whichever output looks the most likely", "Only record the very last value each variable has, once the whole algorithm has finished", "Run every loop exactly once no matter how many times the condition actually says it should repeat, to save time"]}'::jsonb, '{"answer": 0, "explain": "A trace table must be built mechanically, line by line, updating a variable''s column every time that line changes it — including every single pass of a loop, not just the last one."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:learn:198c41c3', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'learn', 'mcq', 1, '{"readingTitle": "Syntax errors", "reading": "<h4>Errors that break the rules of the language</h4>\n<ul>\n<li>A <strong>syntax error</strong> breaks the grammar/rules of the programming language — the program will not run (or translate) at all until it is fixed.</li>\n<li>Common examples: a missing <code>endif</code> / <code>endwhile</code>, a missing bracket, a misspelt keyword, or mismatched quotation marks.</li>\n</ul>\n<div class=\"code-block\">if age &gt;= 18 then\n  print(\"Adult\")\n// missing endif — SYNTAX ERROR: the if statement is never closed</div>\n<ul><li>The translator (interpreter/compiler) usually reports a syntax error with a line number, because it cannot understand the instruction at all.</li></ul>", "question": "Which of these is an example of a SYNTAX error?", "options": ["An if statement that is never closed with its matching endif keyword", "A loop that repeats one time too many because of an incorrect condition", "A calculation that adds two values together when it should have multiplied them", "A condition that uses AND when the algorithm actually needed to use OR instead, giving the wrong result"]}'::jsonb, '{"answer": 0, "explain": "A missing endif breaks the rules of the language, so the program will not run at all — that''s a syntax error. The other options all describe programs that run but give the wrong answer (logic errors)."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:learn:024430ca', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'learn', 'mcq', 1, '{"readingTitle": "Logic errors", "reading": "<h4>Errors that run — but give the wrong answer</h4>\n<ul>\n<li>A <strong>logic error</strong> follows the rules of the language perfectly (it runs without crashing) but produces the <strong>wrong result</strong>, because the programmer''s logic was flawed.</li>\n<li>Common examples: using <code>&lt;</code> where <code>&lt;=</code> was needed (off-by-one), swapping <code>AND</code>/<code>OR</code>, adding instead of multiplying, or using the wrong variable.</li>\n</ul>\n<div class=\"code-block\">total = 0\nfor i = 1 to 10\n  total = total + i\nnext i\naverage = total + 10   // LOGIC ERROR: should be total / 10</div>\n<ul><li>Logic errors are harder to find than syntax errors because the program runs successfully — you have to <strong>trace it</strong> and compare the output to what it should be.</li></ul>", "question": "Which of these is an example of a LOGIC error?", "options": ["A while loop''s counter is never updated inside the loop, so the loop never ends", "A missing closing quotation mark on a string of text being printed to the screen", "The keyword ''pritn'' is typed instead of ''print'', so the translator cannot understand it", "An endwhile keyword is left out completely, so the while loop is never properly closed"]}'::jsonb, '{"answer": 0, "explain": "The loop runs without breaking any language rules, but the missing update means the condition never becomes false — the program runs, just with the wrong (infinite) behaviour. That''s a logic error. The others are all syntax errors."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:learn:b209f5b1', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'learn', 'mcq', 1, '{"readingTitle": "Finding and correcting errors: syntax vs logic", "reading": "<h4>Spotting which kind of error you are looking at</h4>\n<ul>\n<li>Ask: <strong>\"Will this even run?\"</strong> If no — it''s a <strong>syntax</strong> error (fix the broken rule: add the missing keyword/bracket/quote). If it runs but the <strong>output is wrong</strong> — it''s a <strong>logic</strong> error (fix the flawed condition/calculation/variable).</li>\n</ul>\n<div class=\"code-block\">while count &lt; 10\n  print(count)\n  count = count + 1\n// missing endwhile → SYNTAX (program won''t run)\n\nwhile count &lt; 10\n  print(count)\n// missing count = count + 1 → LOGIC (infinite loop, but no syntax error)</div>\n<ul><li>An infinite loop caused by a missing increment is a classic <strong>logic</strong> error: nothing is broken grammatically, the loop condition is just never made false.</li></ul>", "question": "What is the quickest first question to ask when classifying an error as syntax or logic?", "options": ["''Will this program even run?'' — if not, it''s syntax; if it runs but is wrong, it''s logic", "''Is the error found in the first line of the algorithm, or somewhere near the very last line instead?''", "''Does the error involve a loop, or does it involve an if statement instead?''", "''Is the variable name spelled correctly throughout the whole algorithm?''"]}'::jsonb, '{"answer": 0, "explain": "Asking whether the program runs at all separates the two error types instantly: won''t run → syntax; runs but the output is wrong → logic. The line number, construct used and spelling don''t tell you which type it is."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:learn:824181d7', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'learn', 'mcq', 1, '{"readingTitle": "Completing an algorithm", "reading": "<h4>Filling in a missing line or condition</h4>\n<ul>\n<li>\"Complete the algorithm\" questions give you a working algorithm with one or more lines <strong>missing</strong>, and ask you to supply exactly what belongs there so it does what is described.</li>\n<li>Method: work out what the SURROUNDING lines need to be true. Match variable names already in use exactly, and check loop/condition boundaries carefully — off-by-one is the most common slip.</li>\n</ul>\n<div class=\"code-block\">total = 0\nfor i = 1 to ____        // must repeat 5 times → \"5\"\n  total = total + i\nnext i\nprint(____)               // must show the result → \"total\"</div>", "question": "When completing a missing line in a given algorithm, what should you check most carefully?", "options": ["That your line matches the variable names already used, and that any loop bounds are exactly right", "That your line is written in whichever real programming language you personally feel the most comfortable and confident using", "That your line is as short as possible, even if it does not do quite the right job", "That your line comes before the start of the algorithm rather than in the middle of it"]}'::jsonb, '{"answer": 0, "explain": "A completed line must fit its surroundings exactly — using the SAME variable names already in use, and getting loop/condition boundaries exactly right (off-by-one is the classic slip)."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:learn:95f9021a', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'learn', 'mcq', 1, '{"readingTitle": "Refining an algorithm", "reading": "<h4>Making a correct algorithm better</h4>\n<ul>\n<li><strong>Refining</strong> means improving an algorithm that already works — making it more efficient, more readable, or able to cope with more cases — without changing what it is meant to do.</li>\n<li>Common refinements: replacing repeated code with a <strong>loop</strong>, adding <strong>validation</strong> so bad input can''t break it, using better variable names, or combining nested selections into one clearer condition.</li>\n</ul>\n<div class=\"code-compare\">\n<div><p class=\"code-label\">Before</p><div class=\"code-block\">print(input(\"Score 1: \"))\nprint(input(\"Score 2: \"))\nprint(input(\"Score 3: \"))</div></div>\n<div><p class=\"code-label\">Refined</p><div class=\"code-block\">for i = 1 to 3\n  print(input(\"Score \" + i + \": \"))\nnext i</div></div>\n</div>\n<ul><li>The refined version does the same job, but scales to any number of scores just by changing one number.</li></ul>", "question": "What does ''refining'' an algorithm mean?", "options": ["Improving an algorithm that already works, without changing what it is meant to do", "Fixing a syntax error so that a broken program is finally able to run at all", "Rewriting the algorithm from scratch to solve a completely different problem", "Deleting most of the algorithm''s lines so that it becomes as short as it can possibly be, whatever the cost"]}'::jsonb, '{"answer": 0, "explain": "Refining takes a CORRECT algorithm and makes it better — more efficient, readable or robust — without changing what it does. Fixing a syntax error is correcting, not refining."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:learn:65ced110', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'learn', 'mcq', 1, '{"readingTitle": "Nesting: selection inside selection", "reading": "<h4>An if inside another if</h4>\n<ul>\n<li><strong>Nesting</strong> means putting one construct <strong>inside</strong> another. A common form is <strong>selection inside selection</strong>: an inner <code>if</code> only runs once the outer condition has already been met.</li>\n</ul>\n<div class=\"code-block\">if age &gt;= 17 then\n  if hasLicence == \"yes\" then\n    print(\"Can drive\")\n  else\n    print(\"Needs a licence\")\n  endif\nelse\n  print(\"Too young to drive\")\nendif</div>\n<ul><li>The inner <code>if</code> is only reached at all when <code>age &gt;= 17</code> is true — this lets an algorithm test a <strong>second condition</strong> that only makes sense once the first has been satisfied.</li></ul>", "question": "In an algorithm with an if statement nested inside another if statement, when does the INNER if get checked?", "options": ["Only once the outer if''s condition has already been found to be true", "Always, no matter what the outer if''s condition works out to be", "Only if the outer if statement''s condition has been found to be false instead", "Before the outer if statement has even been reached during execution"]}'::jsonb, '{"answer": 0, "explain": "A nested if is only reached — and only checked — once the flow has already entered the outer if''s branch, i.e. once the outer condition is true. It cannot run before the outer if, or if the outer condition was false."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:learn:85a9d375', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'learn', 'mcq', 1, '{"readingTitle": "Nesting: selection and iteration inside a loop", "reading": "<h4>An if inside a loop (and a loop inside a loop)</h4>\n<ul>\n<li>Putting <strong>selection inside iteration</strong> lets a loop make a different decision on <strong>every pass</strong>. Putting <strong>iteration inside iteration</strong> (a loop inside a loop) repeats the inner loop <strong>completely</strong> for every single pass of the outer loop.</li>\n</ul>\n<div class=\"code-block\">for i = 1 to 5\n  n = input(\"Enter a number: \")\n  if n MOD 2 == 0 then\n    print(n + \" is even\")\n  else\n    print(n + \" is odd\")\n  endif\nnext i</div>\n<ul><li>Here the <code>if</code> is nested inside the <code>for</code> loop, so every one of the 5 numbers is tested and labelled individually.</li></ul>", "question": "An if statement is placed inside a for loop. How many times is the if statement checked?", "options": ["Once for every single pass of the for loop", "Only once, no matter how many times the for loop repeats in total", "Exactly twice, regardless of how many passes the for loop actually makes", "Never, because a for loop and an if statement cannot be nested inside each other at all"]}'::jsonb, '{"answer": 0, "explain": "Nesting an if inside a for loop means the if''s condition is evaluated freshly on every pass of the loop — that''s what lets the loop make a different decision each time."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:misc:2abcd004', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking every error that stops a program from working must be a ''logic error''.</p><p><strong>✅ The correct idea:</strong> A <strong>logic</strong> error still RUNS — it just gives the wrong result. An error that stops the program running at all (like a missing <code>endif</code>) is a <strong>syntax</strong> error, because it breaks the rules of the language.</p>", "question": "A program will not run at all because of a missing bracket. What type of error is this?", "options": ["Syntax error", "Logic error", "Runtime error", "Value error"]}'::jsonb, '{"answer": 0, "explain": "An error that stops the program from running breaks the rules of the language — that makes it a syntax error, not a logic error."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:misc:4a32ab77', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Believing a diamond symbol in a flowchart is just another process step.</p><p><strong>✅ The correct idea:</strong> A diamond is specifically a <strong>decision</strong> symbol — it asks a yes/no question and the flow <strong>splits into two branches</strong>. A plain process step (like a calculation) uses a <strong>rectangle</strong> instead, which has only one way in and one way out.</p>", "question": "How many exits does a flowchart rectangle (process) symbol normally have?", "options": ["One", "Two", "Three", "Zero"]}'::jsonb, '{"answer": 0, "explain": "A process rectangle has a single flow of instructions in and out. Two exits (Yes/No) is the signature of a decision diamond, not a process rectangle."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:misc:f0a4c16c', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking a while loop''s missing counter update is a syntax error.</p><p><strong>✅ The correct idea:</strong> The loop''s grammar is perfectly correct — <code>while</code>/<code>endwhile</code> are matched properly, so it <strong>runs</strong>. It just never becomes false, so it repeats forever. Because the program runs (just wrongly), this is a <strong>logic</strong> error, not a syntax error.</p>", "question": "A while loop repeats forever because its counter is never updated inside the loop body. What type of error is this?", "options": ["Logic error", "Syntax error", "Formatting error", "Naming error"]}'::jsonb, '{"answer": 0, "explain": "The loop obeys every rule of the language and runs — it just never stops, because the condition is never made false. That is a logic error."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:misc:4de0a983', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Confusing a structure diagram with a flowchart.</p><p><strong>✅ The correct idea:</strong> A <strong>structure diagram</strong> is a hierarchy chart showing how a problem is <strong>decomposed</strong> into sub-tasks — it has no decisions or arrows showing execution order. A <strong>flowchart</strong> shows the actual <strong>step-by-step logic</strong> of an algorithm, including decisions (diamonds) and loops.</p>", "question": "Which diagram shows decisions and loops using standard symbols like a diamond?", "options": ["A flowchart", "A structure diagram", "An IPO table", "A trace table"]}'::jsonb, '{"answer": 0, "explain": "A flowchart shows an algorithm''s step-by-step logic, including decisions and loops. A structure diagram only shows decomposition into sub-tasks, with no decisions."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:misc:6c347b91', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking ''refining'' an algorithm means fixing a mistake in it.</p><p><strong>✅ The correct idea:</strong> Refining assumes the algorithm <strong>already works correctly</strong>. It means making it <strong>better</strong> — more efficient, more readable, or able to handle more cases — without changing what it does. Fixing a mistake so it works correctly is <strong>correcting</strong> it, a different step.</p>", "question": "An algorithm already gives the correct answer. A programmer rewrites it to be shorter and easier to read. What is this called?", "options": ["Refining", "Correcting", "Debugging", "Testing"]}'::jsonb, '{"answer": 0, "explain": "Improving a CORRECT algorithm — without changing its behaviour — is refining. Correcting and debugging both imply the algorithm was wrong to begin with."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:misc:f61b701c', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Believing a trace table only needs the FINAL value of each variable.</p><p><strong>✅ The correct idea:</strong> A trace table must record a variable''s value <strong>every time it changes</strong> — including on <strong>every pass</strong> of a loop — not just the value it ends up with. Skipping passes is how marks are lost, even if the final answer looks right.</p>", "question": "A loop runs 4 times, changing ''total'' on every pass. How many values of ''total'' should a full trace table show?", "options": ["Four — one for every pass of the loop", "One — just the final value", "Two — the first and the last only", "None, because totals are not usually traced"]}'::jsonb, '{"answer": 0, "explain": "A trace table records a value every time it changes, so a 4-pass loop needs 4 rows for ''total'' — not just the final one."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:tips:44760bd5', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'tips', 'mcq', 1, '{"readingTitle": "tip — How to answer ''complete the algorithm'' questions", "reading": "<p>\"Complete the algorithm\" questions give you a working algorithm with one or two lines removed — you don''t need to write the whole thing, just work out exactly what belongs in the gap.</p>\n<ul>\n<li>Read the <strong>whole</strong> algorithm first, including the lines AFTER the gap — they often reveal what the missing line must produce.</li>\n<li>Check the <strong>variable names</strong> already used and match them <strong>exactly</strong> (case and spelling matter).</li>\n<li>Check loop and condition <strong>boundaries</strong> carefully — \"1 to 5\" vs \"1 to 4\" is the classic off-by-one slip that loses marks.</li>\n</ul>\n<p><strong>Example:</strong> if the line after a for loop is <code>print(total)</code>, the loop itself must be building up a running total called <code>total</code> — that tells you what to write inside the loop body.</p>", "question": "What should you read FIRST before deciding what belongs in a missing line of an algorithm?", "options": ["The whole algorithm, including the lines that come after the gap", "On every single line of the algorithm you are given, regardless of whether it changes anything at all", "Only the title given to the exam question itself", "The mark scheme, which is always printed just below the question"]}'::jsonb, '{"answer": 0, "explain": "Reading the lines AFTER the gap often reveals exactly what the missing line needs to produce, e.g. a variable that gets printed later."}'::jsonb),
('computer-science:2-1-2-designing-creating-and-refining-algorithms:tips:c267ea0c', 'computer-science', 'computer-science:2-1-2-designing-creating-and-refining-algorithms', '2.1.2 Designing, Creating and Refining Algorithms', 'tips', 'mcq', 1, '{"readingTitle": "explain — Classifying syntax vs logic errors fast", "reading": "<p>\"Is this a syntax error or a logic error?\" is one of the most repeated question types on this topic. Use one quick test:</p>\n<ul>\n<li>Ask: <strong>\"Would this program even run?\"</strong></li>\n<li>If <strong>no</strong> — a rule of the language has been broken (missing keyword, bracket, quote) — it''s a <strong>syntax</strong> error.</li>\n<li>If <strong>yes</strong>, but the <strong>output is wrong</strong> — the language rules are fine, the programmer''s reasoning was flawed — it''s a <strong>logic</strong> error.</li>\n</ul>\n<p><strong>Watch for:</strong> a missing loop-update (infinite loop), the wrong comparison (<code>&lt;</code> instead of <code>&lt;=</code>), or a swapped <code>AND</code>/<code>OR</code> — these all still RUN, so they are logic errors, even though the result is clearly broken.</p>", "question": "A condition uses OR when it should have used AND, so the algorithm behaves incorrectly. What type of error is this?", "options": ["Logic error", "Syntax error", "Grammar error", "Compilation error"]}'::jsonb, '{"answer": 0, "explain": "Swapping AND and OR doesn''t break any language rule — the program runs — it just makes the wrong decision. That is a logic error."}'::jsonb)
